package com.example.securebank.data;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

import java.math.BigDecimal;
import java.util.Currency;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public final class InMemoryAccountRepository implements AccountRepository {
    private final Map<String, Account> accounts = new ConcurrentHashMap<>();
    private final Map<String, AccountBalance> balances = new ConcurrentHashMap<>();

    public InMemoryAccountRepository() {
        Account a = new Account("CHK-1001", "Checking");
        Account b = new Account("SAV-2001", "Savings");
        upsertAccount(a);
        upsertAccount(b);

        upsertBalance(new AccountBalance(a, new Money(new BigDecimal("1250.00"), Currency.getInstance("USD"))));
        upsertBalance(new AccountBalance(b, new Money(new BigDecimal("5400.00"), Currency.getInstance("USD"))));
    }

    @Override
    @Nullable
    public AccountBalance getBalance(@NonNull String accountId) {
        return balances.get(accountId);
    }

    @Override
    public void upsertBalance(@NonNull AccountBalance balance) {
        balances.put(balance.getAccount().getAccountId(), balance);
    }

    @Override
    @Nullable
    public Account getAccount(@NonNull String accountId) {
        return accounts.get(accountId);
    }

    @Override
    public void upsertAccount(@NonNull Account account) {
        accounts.put(account.getAccountId(), account);
        if (!balances.containsKey(account.getAccountId())) {
            balances.put(account.getAccountId(), AccountBalance.initial(account));
        }
    }
}

