package com.example.securebank.domain;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

import com.example.securebank.data.Account;
import com.example.securebank.data.AccountBalance;
import com.example.securebank.data.AccountRepository;
import com.example.securebank.data.Money;
import com.example.securebank.data.TransactionRequest;
import com.example.securebank.data.TransactionResult;
import com.example.securebank.security.SimpleAuthorizer;

import java.util.concurrent.locks.ReentrantLock;

public final class TransactionProcessor {
    private final AccountRepository repo;
    private final SimpleAuthorizer authorizer;
    private final ReentrantLock lock = new ReentrantLock(true);

    public TransactionProcessor(@NonNull AccountRepository repo, @NonNull SimpleAuthorizer authorizer) {
        if (repo == null) throw new NullPointerException("repo");
        if (authorizer == null) throw new NullPointerException("authorizer");
        this.repo = repo;
        this.authorizer = authorizer;
    }

    @NonNull
    public TransactionResult process(@NonNull String userId, @NonNull TransactionRequest request) {
        if (!authorizer.isAuthorized(userId)) {
            return TransactionResult.declined("Not authorized");
        }

        lock.lock();
        try {
            switch (request.getType()) {
                case CREDIT:
                    return credit(request.getToAccountId(), request.getAmount());
                case DEBIT:
                    return debit(request.getFromAccountId(), request.getAmount());
                case TRANSFER:
                    return transfer(request.getFromAccountId(), request.getToAccountId(), request.getAmount());
                default:
                    return TransactionResult.error("Unsupported transaction type");
            }
        } catch (Exception e) {
            return TransactionResult.error("Processing error");
        } finally {
            lock.unlock();
        }
    }

    @NonNull
    private TransactionResult credit(@Nullable String toAccountId, @NonNull Money amount) {
        if (toAccountId == null) return TransactionResult.error("Missing destination account");
        AccountBalance toBal = repo.getBalance(toAccountId);
        Account toAcc = repo.getAccount(toAccountId);
        if (toAcc == null) return TransactionResult.declined("Unknown destination account");
        if (toBal == null) toBal = AccountBalance.initial(toAcc);

        if (amount.getAmount().signum() <= 0) return TransactionResult.declined("Invalid amount");

        AccountBalance updated = new AccountBalance(toAcc, toBal.getAvailable().plus(amount));
        repo.upsertBalance(updated);
        return TransactionResult.approved("Credit posted");
    }

    @NonNull
    private TransactionResult debit(@Nullable String fromAccountId, @NonNull Money amount) {
        if (fromAccountId == null) return TransactionResult.error("Missing source account");
        AccountBalance fromBal = repo.getBalance(fromAccountId);
        Account fromAcc = repo.getAccount(fromAccountId);
        if (fromAcc == null) return TransactionResult.declined("Unknown source account");
        if (fromBal == null) fromBal = AccountBalance.initial(fromAcc);

        if (amount.getAmount().signum() <= 0) return TransactionResult.declined("Invalid amount");
        if (fromBal.getAvailable().compareTo(amount) < 0) return TransactionResult.declined("Insufficient funds");

        AccountBalance updated = new AccountBalance(fromAcc, fromBal.getAvailable().minus(amount));
        repo.upsertBalance(updated);
        return TransactionResult.approved("Debit posted");
    }

    @NonNull
    private TransactionResult transfer(@Nullable String fromAccountId, @Nullable String toAccountId, @NonNull Money amount) {
        if (fromAccountId == null || toAccountId == null) return TransactionResult.error("Missing account");
        if (fromAccountId.equals(toAccountId)) return TransactionResult.declined("Accounts must be different");

        Account fromAcc = repo.getAccount(fromAccountId);
        Account toAcc = repo.getAccount(toAccountId);
        if (fromAcc == null || toAcc == null) return TransactionResult.declined("Unknown account");

        AccountBalance fromBal = repo.getBalance(fromAccountId);
        AccountBalance toBal = repo.getBalance(toAccountId);
        if (fromBal == null) fromBal = AccountBalance.initial(fromAcc);
        if (toBal == null) toBal = AccountBalance.initial(toAcc);

        if (amount.getAmount().signum() <= 0) return TransactionResult.declined("Invalid amount");
        if (!fromBal.getAvailable().getCurrency().equals(amount.getCurrency())) return TransactionResult.declined("Currency mismatch");
        if (!toBal.getAvailable().getCurrency().equals(amount.getCurrency())) return TransactionResult.declined("Currency mismatch");
        if (fromBal.getAvailable().compareTo(amount) < 0) return TransactionResult.declined("Insufficient funds");

        repo.upsertBalance(new AccountBalance(fromAcc, fromBal.getAvailable().minus(amount)));
        repo.upsertBalance(new AccountBalance(toAcc, toBal.getAvailable().plus(amount)));
        return TransactionResult.approved("Transfer posted");
    }
}

package com.example.securebank.ui;

import android.os.Bundle;
import android.text.InputType;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.Spinner;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import com.example.securebank.data.Account;
import com.example.securebank.data.AccountBalance;
import com.example.securebank.data.InMemoryAccountRepository;
import com.example.securebank.data.Money;
import com.example.securebank.data.TransactionRequest;
import com.example.securebank.data.TransactionResult;
import com.example.securebank.domain.TransactionProcessor;
import com.example.securebank.security.AllowAllAuthorizer;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Currency;
import java.util.List;

public class MainActivity extends AppCompatActivity {

    private InMemoryAccountRepository repo;
    private TransactionProcessor processor;

    private Spinner fromSpinner;
    private Spinner toSpinner;
    private TextView fromBalance;
    private TextView toBalance;
    private EditText amountEdit;
    private TextView statusText;

    private final List<Account> demoAccounts = new ArrayList<>();

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        repo = new InMemoryAccountRepository();
        processor = new TransactionProcessor(repo, new AllowAllAuthorizer());

        demoAccounts.add(repo.getAccount("CHK-1001"));
        demoAccounts.add(repo.getAccount("SAV-2001"));

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int pad = (int) (16 * getResources().getDisplayMetrics().density);
        root.setPadding(pad, pad, pad, pad);

        TextView title = new TextView(this);
        title.setText("SecureBank - Transactions");
        title.setTextSize(20f);
        root.addView(title);

        fromSpinner = new Spinner(this);
        toSpinner = new Spinner(this);

        ArrayAdapter<String> adapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_item, accountLabels());
        adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        fromSpinner.setAdapter(adapter);
        toSpinner.setAdapter(adapter);

        root.addView(label("From Account"));
        root.addView(fromSpinner);
        fromBalance = new TextView(this);
        root.addView(fromBalance);

        root.addView(label("To Account"));
        root.addView(toSpinner);
        toBalance = new TextView(this);
        root.addView(toBalance);

        root.addView(label("Amount (USD)"));
        amountEdit = new EditText(this);
        amountEdit.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);
        amountEdit.setHint("0.00");
        root.addView(amountEdit);

        LinearLayout buttons = new LinearLayout(this);
        buttons.setOrientation(LinearLayout.HORIZONTAL);

        Button btnTransfer = new Button(this);
        btnTransfer.setText("Transfer");
        buttons.addView(btnTransfer, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));

        Button btnCredit = new Button(this);
        btnCredit.setText("Credit To");
        buttons.addView(btnCredit, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));

        Button btnDebit = new Button(this);
        btnDebit.setText("Debit From");
        buttons.addView(btnDebit, new LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f));

        root.addView(buttons);

        statusText = new TextView(this);
        root.addView(statusText);

        setContentView(root);

        View.OnClickListener refresh = v -> refreshBalances();
        fromSpinner.setOnItemSelectedListener(new SimpleItemSelectedListener(refresh));
        toSpinner.setOnItemSelectedListener(new SimpleItemSelectedListener(refresh));
        refreshBalances();

        btnTransfer.setOnClickListener(v -> {
            Money amount = parseAmount();
            if (amount == null) return;
            String fromId = selectedAccountId(fromSpinner);
            String toId = selectedAccountId(toSpinner);
            TransactionResult res = processor.process("demoUser", new TransactionRequest(TransactionRequest.Type.TRANSFER, fromId, toId, amount, "UI transfer"));
            showResult(res);
            refreshBalances();
        });

        btnCredit.setOnClickListener(v -> {
            Money amount = parseAmount();
            if (amount == null) return;
            String toId = selectedAccountId(toSpinner);
            TransactionResult res = processor.process("demoUser", new TransactionRequest(TransactionRequest.Type.CREDIT, null, toId, amount, "UI credit"));
            showResult(res);
            refreshBalances();
        });

        btnDebit.setOnClickListener(v -> {
            Money amount = parseAmount();
            if (amount == null) return;
            String fromId = selectedAccountId(fromSpinner);
            TransactionResult res = processor.process("demoUser", new TransactionRequest(TransactionRequest.Type.DEBIT, fromId, null, amount, "UI debit"));
            showResult(res);
            refreshBalances();
        });
    }

    private void showResult(TransactionResult res) {
        statusText.setText(res.getStatus().name() + ": " + res.getMessage() + " (id " + res.getTransactionId() + ")");
    }

    private void refreshBalances() {
        String fromId = selectedAccountId(fromSpinner);
        String toId = selectedAccountId(toSpinner);

        fromBalance.setText("Balance: " + displayBalance(fromId));
        toBalance.setText("Balance: " + displayBalance(toId));
    }

    private String displayBalance(String accountId) {
        AccountBalance bal = repo.getBalance(accountId);
        if (bal == null) return "N/A";
        return bal.getAvailable().toString();
    }

    private TextView label(String text) {
        TextView tv = new TextView(this);
        tv.setText(text);
        return tv;
    }

    private List<String> accountLabels() {
        List<String> labels = new ArrayList<>();
        for (Account a : demoAccounts) {
            if (a != null) labels.add(a.getDisplayName() + " (" + a.getAccountId() + ")");
        }
        return labels;
    }

    private String selectedAccountId(Spinner spinner) {
        int idx = spinner.getSelectedItemPosition();
        if (idx < 0 || idx >= demoAccounts.size()) return "CHK-1001";
        Account a = demoAccounts.get(idx);
        return a != null ? a.getAccountId() : "CHK-1001";
    }

    @Nullable
    private Money parseAmount() {
        String raw = amountEdit.getText() != null ? amountEdit.getText().toString().trim() : "";
        if (raw.isEmpty()) {
            statusText.setText("ERROR: Enter amount");
            return null;
        }
        try {
            BigDecimal v = new BigDecimal(raw);
            return new Money(v, Currency.getInstance("USD"));
        } catch (Exception e) {
            statusText.setText("ERROR: Invalid amount");
            return null;
        }
    }
}

package com.example.securebank.ui;

import android.view.View;
import android.widget.AdapterView;

public final class SimpleItemSelectedListener implements AdapterView.OnItemSelectedListener {
    private final View.OnClickListener onChange;

    public SimpleItemSelectedListener(View.OnClickListener onChange) {
        this.onChange = onChange;
    }

    @Override
    public void onItemSelected(AdapterView<?> parent, View view, int position, long id) {
        if (onChange != null) onChange.onClick(parent);
    }

    @Override
    public void onNothingSelected(AdapterView<?> parent) {
        if (onChange != null) onChange.onClick(parent);
    }
}